      optionTitlesRequired: isDe ? 'Alle Optionstitel sind erforderlich' : isEs ? 'Todos los títulos de opción son obligatorios' : 'All option titles are required',
      valueRequired: isDe ? 'Vorgeschlagener Wert ist erforderlich' : isEs ? 'El valor propuesto es obligatorio' : 'Proposed value is required',
