      proposalPeriod: isDe ? 'Dokumentvorschlagszeitraum muss eine positive Ganzzahl (Tage) sein' : isEs ? 'El periodo de propuesta debe ser un entero positivo (días)' : 'Document proposal period must be a positive integer (days)',
      cutoffRange: isDe ? 'Abschnittsvorschlags-Stopp muss eine Ganzzahl zwischen 0 und 365 Tagen sein' : isEs ? 'El cierre de propuestas de párrafo debe ser un entero entre 0 y 365 días' : 'Paragraph proposal cutoff must be an integer between 0 and 365 days',
